import { GoogleGenAI, Type } from "@google/genai";
import { Language, LexicalEntry } from "../types";

const generateId = () => {
  if (typeof crypto !== 'undefined' && crypto.randomUUID) {
    return crypto.randomUUID();
  }
  return 'lex-' + Date.now() + '-' + Math.random().toString(36).substring(2, 11);
};

function shuffleArray<T>(array: T[]): T[] {
  const newArray = [...array];
  for (let i = newArray.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [newArray[i], newArray[j]] = [newArray[j], newArray[i]];
  }
  return newArray;
}

/**
 * PHASE 1: Fast Core Translation
 */
export async function translateWordCore(
  query: string, 
  sourceLanguage: Language, 
  targetLanguage: Language
): Promise<LexicalEntry> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `System: Philological Lexicon. 
Task: Analyze and translate "${query}" from ${sourceLanguage} to ${targetLanguage}.
Precision Requirements:
1. Provide the primary translation in ${targetLanguage}.
2. Provide synonyms of "${query}" in ${sourceLanguage}.
3. Provide semantic variations in ${targetLanguage}.
4. If ${sourceLanguage} is not Uzbek, provide the CEFR level (A1-C2).
5. If ${sourceLanguage} is German, include gender and plural forms.
Output: JSON.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      thinkingConfig: { thinkingBudget: 0 },
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          term: { type: Type.STRING },
          mainTranslation: { type: Type.STRING },
          partOfSpeech: { type: Type.STRING },
          gender: { type: Type.STRING },
          plural: { type: Type.STRING },
          cefrLevel: { type: Type.STRING, description: "CEFR Level (e.g., A1, B2)" },
          synonyms: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING }
          },
          variations: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                text: { type: Type.STRING },
                confidence: { type: Type.NUMBER }
              }
            }
          }
        },
        required: ["term", "mainTranslation", "partOfSpeech"]
      }
    }
  });

  const rawData = JSON.parse(response.text || '{}');

  return {
    id: generateId(),
    term: rawData.term || query,
    normalizedTerm: query.toLowerCase().trim(),
    mainTranslation: rawData.mainTranslation,
    sourceLang: sourceLanguage,
    targetLang: targetLanguage,
    cefrLevel: sourceLanguage !== 'Uzbek' ? rawData.cefrLevel : undefined,
    philology: {
      etymology: "", 
      partOfSpeech: rawData.partOfSpeech,
      gender: rawData.gender,
      plural: rawData.plural
    },
    culture: { usage: "", register: 'neutral', notes: "" },
    synonyms: rawData.synonyms || [],
    variations: (rawData.variations || []).map((v: any) => ({ ...v, source: 'ai' })),
    literature: [],
    realLifeSentences: [],
    idioms: [],
    timestamp: Date.now()
  };
}

/**
 * PHASE 2: Archival Enrichment
 */
export async function enrichLexicalEntry(entry: LexicalEntry): Promise<Partial<LexicalEntry>> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `Senior Philologist Mode: Provide scholarly enrichment for "${entry.term}" (${entry.sourceLang} to ${entry.targetLang}). 
  Include:
  1. Detailed Etymology.
  2. TWO simplified literary manifestations from books, poems, or movies.
  3. TWO Specific Usage Examples: 
     - Item 1: One simple natural sentence showing common usage.
     - Item 2: One simple real-life idiomatic or metaphorical application.
     Focus on authenticity and cultural resonance. These will be stored as idioms in the archives.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 0 },
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            etymology: { type: Type.STRING },
            usage: { type: Type.STRING },
            register: { type: Type.STRING },
            notes: { type: Type.STRING },
            literature: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  text: { type: Type.STRING },
                  translation: { type: Type.STRING },
                  source: { type: Type.STRING },
                  author: { type: Type.STRING }
                }
              },
              minItems: 2
            },
            idioms: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  text: { type: Type.STRING },
                  translation: { type: Type.STRING },
                  context: { type: Type.STRING, description: "Label as 'Natural Usage' or 'Idiom'" }
                }
              },
              minItems: 2,
              maxItems: 2
            }
          }
        }
      }
    });

    const raw = JSON.parse(response.text || '{}');
    return {
      philology: { ...entry.philology, etymology: raw.etymology || "Archival retrieval synchronized." },
      culture: {
        usage: raw.usage || "Standard scholarly use",
        register: raw.register || 'neutral',
        notes: raw.notes || ""
      },
      literature: raw.literature || [],
      realLifeSentences: raw.idioms || [], // Mirroring for backward compatibility
      idioms: raw.idioms || []
    };
  } catch (err) {
    return {
      philology: { ...entry.philology, etymology: "Archival record retrieved." }
    };
  }
}

/**
 * Scholarly Daily Insight
 */
export async function getDailyInsight() {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = "Generate a sophisticated 'Linguistic Fact of the Day' relating to the intersection of German, Uzbek, Arabic, or Russian. Focus on etymology or cognates. Output as JSON.";

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            fact: { type: Type.STRING },
            source: { type: Type.STRING }
          },
          required: ["title", "fact"]
        }
      }
    });
    return JSON.parse(response.text || '{}');
  } catch (err) {
    return { 
      title: "Lexical Continuity", 
      fact: "Cross-cultural linguistics reveal the hidden threads connecting disparate civilizations through shared roots.",
      source: "Archival Preface"
    };
  }
}

/**
 * Arena Quiz Generation
 */
export async function generateQuiz(entries: LexicalEntry[]) {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const context = entries.map(e => `${e.term} (${e.sourceLang}) <-> ${e.mainTranslation} (${e.targetLang})`).join(", ");

  const prompt = `Task: Create a simple multiple-choice vocabulary quiz based on these translations: ${context}.
Rules:
1. Max 2 simple questions per word.
2. Question style: Use ONLY the word itself as the question (e.g. "Tisch").
3. Directionality:
   - Type A: Question is Source Term -> Options are Target Translations.
   - Type B: Question is Target Translation -> Options are Source Terms.
4. Options style: Provide exactly 3 options. Options must be simple single words.
5. Distractors: Must be words of the same language as the correct answer, ideally unrelated or commonly confused.
6. Example: 
   Question: "Tisch"
   Options: ["ruchka", "stol", "chiroq"]
   CorrectAnswer: "stol"
7. Output format: JSON Array of objects.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 0 },
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              question: { type: Type.STRING },
              correctAnswer: { type: Type.STRING },
              options: { type: Type.ARRAY, items: { type: Type.STRING } },
              explanation: { type: Type.STRING }
            },
            required: ["question", "correctAnswer", "options", "explanation"]
          }
        }
      }
    });

    const questions = JSON.parse(response.text || '[]');
    return questions.map((q: any) => ({
      ...q,
      options: shuffleArray(q.options)
    }));
  } catch (err) {
    console.error("Quiz gen error:", err);
    return [];
  }
}
